#include<bits/stdc++.h>
#define LL long long
#define UInt unsigned int
#define ULL unsigned long long
#define LD long double
#define pii pair<int,int>
#define pLL pair<LL,LL>
#define pDD pair<LD,LD>
#define fr first
#define se second
#define pb push_back
#define isr insert
using namespace std;
const int N = 2.2e7+5;
int n,ma[N],Ans;string s,t;
int read(){
    int su=0,pp=1;char ch=getchar();
    while(ch<'0'||ch>'9'){if(ch=='-')pp=-1;ch=getchar();}
    while(ch>='0'&&ch<='9'){su=su*10+ch-'0';ch=getchar();}
    return su*pp;
}

int main(){
    cin>>t;s=" ";
    for(char c:t)s+=c,s+='#';
    s.pop_back();n=s.size()-1;
    for(int i=1,l=0,r=-1;i<=n;i++){
        int len=(i>r?1:min(ma[l+r-i],r-i+1));
        while(i-len>=1&&i+len<=n&&s[i-len]==s[i+len])len++;
        ma[i]=len,Ans=max(Ans,len-(s[i+len-1]=='#'));
        if(i+len-1>r)l=i-len+1,r=i+len-1;
    }cout<<Ans<<"\n";
    return 0;
}
